package com.example.payment.ws;

import javax.jws.WebService;

@WebService(endpointInterface = "com.example.payment.ws.PaymentGatewayService",
            serviceName = "PaymentGatewayService",
            portName = "PaymentGatewayServicePort",
            targetNamespace = "http://ws.payment.example.com/")
public class PaymentGatewayServiceImpl implements PaymentGatewayService {

    @Override
    public PaymentResponse processPayment(PaymentRequest request) {
        System.out.println("Processing payment request: " + request.getTransactionId());

        try {
            Thread.sleep(500); // Simulate network latency/processing time

            if (request.getAmount() <= 0) {
                return new PaymentResponse(false, request.getTransactionId(), "Invalid amount.", null);
            }
            if (!isValidCardNumber(request.getCardNumber())) {
                return new PaymentResponse(false, request.getTransactionId(), "Invalid card number.", null);
            }
            if (!isValidExpiryDate(request.getExpiryDate())) {
                return new PaymentResponse(false, request.getTransactionId(), "Invalid expiry date.", null);
            }
            if (!isValidCvv(request.getCvv())) {
                return new PaymentResponse(false, request.getTransactionId(), "Invalid CVV.", null);
            }

            String authorizationCode = "AUTH-" + System.currentTimeMillis();
            System.out.println("Payment approved for transaction: " + request.getTransactionId() + " with code: " + authorizationCode);
            return new PaymentResponse(true, request.getTransactionId(), "Payment successful.", authorizationCode);

        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            System.err.println("Payment processing interrupted for: " + request.getTransactionId());
            return new PaymentResponse(false, request.getTransactionId(), "Payment processing interrupted.", null);
        } catch (Exception e) {
            System.err.println("An unexpected error occurred during payment processing: " + e.getMessage());
            return new PaymentResponse(false, request.getTransactionId(), "An internal server error occurred.", null);
        }
    }

    private boolean isValidCardNumber(String cardNumber) {
        return cardNumber != null && cardNumber.matches("\\d{13,19}"); // Basic regex, not Luhn
    }

    private boolean isValidExpiryDate(String expiryDate) {
        if (expiryDate == null || !expiryDate.matches("(0[1-9]|1[0-2])/(\\d{2})")) {
            return false;
        }
        // A real system would parse MM/YY and validate against current date.
        return true;
    }

    private boolean isValidCvv(String cvv) {
        return cvv != null && cvv.matches("\\d{3,4}");
    }
}

package com.example.payment.handler;

import com.example.payment.util.SOAPUtil;
import com.example.payment.util.TimestampCache;

import javax.xml.namespace.QName;
import javax.xml.soap.SOAPConstants;
import javax.xml.soap.SOAPFault;
import javax.xml.soap.SOAPMessage;
import javax.xml.ws.handler.MessageContext;
import javax.xml.ws.handler.soap.SOAPHandler;
import javax.xml.ws.handler.soap.SOAPMessageContext;
import javax.xml.ws.soap.SOAPFaultException;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;

public class SecurityHeaderHandler implements SOAPHandler<SOAPMessageContext> {

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outboundProperty = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        if (!outboundProperty) { // Inbound message
            try {
                SOAPMessage soapMessage = context.getMessage();
                System.out.println("Incoming SOAP message received by handler for validation.");
                // For debugging, uncomment to print message:
                // soapMessage.writeTo(System.out);
                // System.out.println("\n--- End of Message ---");

                Map<String, String> timestampData = SOAPUtil.getTimestampFromSecurityHeader(soapMessage);

                if (timestampData == null || timestampData.isEmpty() || !timestampData.containsKey("Created")) {
                    System.err.println("WS-Security Timestamp header missing or incomplete.");
                    throw new SOAPFaultException(createSOAPFault(soapMessage, "MissingSecurityHeader", "WS-Security Timestamp header is required."));
                }

                String timestampId = timestampData.get("Id");
                String created = timestampData.get("Created");
                String expires = timestampData.get("Expires");

                System.out.println("Timestamp extracted: Id=" + (timestampId != null ? timestampId : "N/A") + ", Created=" + created + ", Expires=" + (expires != null ? expires : "N/A"));

                if (!TimestampCache.isValidTimestamp(timestampId, created, expires)) {
                    System.err.println("Timestamp validation failed or replay detected.");
                    throw new SOAPFaultException(createSOAPFault(soapMessage, "TimestampValidationFailed", "Timestamp is invalid or a replay."));
                }

                System.out.println("WS-Security Timestamp validated successfully.");

            } catch (SOAPFaultException e) {
                throw e;
            } catch (Exception e) {
                System.err.println("Error in SecurityHeaderHandler: " + e.getMessage());
                try {
                    throw new SOAPFaultException(createSOAPFault(context.getMessage(), "HandlerProcessingError", "An error occurred while processing security headers: " + e.getMessage()));
                } catch (Exception ex) {
                    throw new RuntimeException("Failed to create SOAP fault after handler error: " + ex.getMessage(), ex);
                }
            }
        }
        return true;
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        System.err.println("Handler caught a SOAP fault.");
        return true;
    }

    @Override
    public void close(MessageContext context) {
        // No resources to close
    }

    @Override
    public Set<QName> getHeaders() {
        // This handler processes the WS-Security header.
        Set<QName> headers = new HashSet<>();
        headers.add(new QName(SOAPUtil.WSS_SECURITY_NS, "Security", "wsse"));
        return headers;
    }

    private SOAPFault createSOAPFault(SOAPMessage soapMessage, String faultCode, String faultString) throws Exception {
        SOAPFault fault = soapMessage.getSOAPPart().getEnvelope().getBody().addFault();
        // Using SOAP 1.1 fault code for simplicity. For SOAP 1.2, use SOAPConstants.URI_NS_SOAP_1_2_ENVELOPE.
        fault.setFaultCode(new QName(SOAPConstants.URI_NS_SOAP_1_1_ENVELOPE, faultCode));
        fault.setFaultString(faultString);
        return fault;
    }
}

