package com.example.payment.util;

import org.w3c.dom.Node;

import javax.xml.soap.SOAPException;
import javax.xml.soap.SOAPHeader;
import javax.xml.soap.SOAPMessage;
import javax.xml.xpath.XPath;
import javax.xml.xpath.XPathConstants;
import javax.xml.xpath.XPathExpressionException;
import javax.xml.xpath.XPathFactory;
import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;

public class SOAPUtil {

    public static final String WSS_SECURITY_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    public static final String WSS_UTILITY_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";

    private static final XPathFactory XPATH_FACTORY = XPathFactory.newInstance();

    // Helper class for namespace context to resolve prefixes in XPath
    private static class WSSE_NamespaceContext implements javax.xml.namespace.NamespaceContext {
        private final Map<String, String> prefixMap = new HashMap<>();

        public WSSE_NamespaceContext() {
            prefixMap.put("wsse", WSS_SECURITY_NS);
            prefixMap.put("wsu", WSS_UTILITY_NS);
            prefixMap.put("soapenv", "http://schemas.xmlsoap.org/soap/envelope/");
        }

        @Override
        public String getNamespaceURI(String prefix) {
            return prefixMap.getOrDefault(prefix, null);
        }

        @Override
        public String getPrefix(String namespaceURI) {
            for (Map.Entry<String, String> entry : prefixMap.entrySet()) {
                if (entry.getValue().equals(namespaceURI)) {
                    return entry.getKey();
                }
            }
            return null;
        }

        @Override
        public java.util.Iterator<String> getPrefixes(String namespaceURI) {
            Set<String> prefixes = new HashSet<>();
            for (Map.Entry<String, String> entry : prefixMap.entrySet()) {
                if (entry.getValue().equals(namespaceURI)) {
                    prefixes.add(entry.getKey());
                }
            }
            return prefixes.iterator();
        }
    }

    public static Map<String, String> getTimestampFromSecurityHeader(SOAPMessage soapMessage) throws SOAPException {
        SOAPHeader header = soapMessage.getSOAPPart().getEnvelope().getHeader();
        if (header == null) {
            return null;
        }

        XPath xpath = XPATH_FACTORY.newXPath();
        xpath.setNamespaceContext(new WSSE_NamespaceContext());

        try {
            // Find wsse:Security element in the SOAP Header
            Node securityNode = (Node) xpath.evaluate("//soapenv:Header/wsse:Security", header, XPathConstants.NODE);

            if (securityNode == null) {
                return null;
            }

            // Find wsu:Timestamp element within wsse:Security
            Node timestampNode = (Node) xpath.evaluate("wsu:Timestamp", securityNode, XPathConstants.NODE);

            if (timestampNode == null) {
                return null;
            }

            Map<String, String> timestampData = new HashMap<>();

            // Extract wsu:Id attribute from wsu:Timestamp
            String timestampId = timestampNode.getAttributes().getNamedItemNS(WSS_UTILITY_NS, "Id") != null ?
                                 timestampNode.getAttributes().getNamedItemNS(WSS_UTILITY_NS, "Id").getNodeValue() : null;
            timestampData.put("Id", timestampId);

            // Extract wsu:Created and wsu:Expires elements' text content
            Node createdNode = (Node) xpath.evaluate("wsu:Created", timestampNode, XPathConstants.NODE);
            if (createdNode != null) {
                timestampData.put("Created", createdNode.getTextContent());
            }

            Node expiresNode = (Node) xpath.evaluate("wsu:Expires", timestampNode, XPathConstants.NODE);
            if (expiresNode != null) {
                timestampData.put("Expires", expiresNode.getTextContent());
            }

            return timestampData;

        } catch (XPathExpressionException e) {
            throw new SOAPException("Error evaluating XPath for WS-Security timestamp", e);
        }
    }
}

package com.example.payment.util;

import java.time.Instant;
import java.time.ZonedDateTime;
import java.time.format.DateTimeParseException;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

public class TimestampCache {

    private static final ConcurrentHashMap<String, Instant> activeTimestamps = new ConcurrentHashMap<>();
    private static final long MAX_AGE_SECONDS = 300; // 5 minutes max age for a timestamp if no explicit Expires
    private static final long CLOCK_SKEW_TOLERANCE_SECONDS = 60; // Allow timestamps to be up to 60 seconds in the future
    private static final long CLEANUP_INTERVAL_SECONDS = 60;

    private static final ScheduledExecutorService scheduler = Executors.newSingleThreadScheduledExecutor(r -> {
        Thread t = Executors.defaultThreadFactory().newThread(r);
        t.setDaemon(true); // Allow JVM to exit
        return t;
    });

    static {
        scheduler.scheduleAtFixedRate(TimestampCache::cleanupExpiredTimestamps, 0, CLEANUP_INTERVAL_SECONDS, TimeUnit.SECONDS);
    }

    private static void cleanupExpiredTimestamps() {
        Instant now = Instant.now();
        activeTimestamps.entrySet().removeIf(entry -> entry.getValue().isBefore(now));
    }

    public static synchronized boolean isValidTimestamp(String timestampId, String created, String expires) {
        if (created == null || created.isEmpty()) {
            System.err.println("Timestamp validation failed: 'wsu:Created' is mandatory.");
            return false;
        }

        Instant createdInstant;
        try {
            createdInstant = ZonedDateTime.parse(created).toInstant();
        } catch (DateTimeParseException e) {
            System.err.println("Timestamp validation failed: Invalid 'wsu:Created' format: " + created);
            return false;
        }

        Instant now = Instant.now();

        // 1. Check if the timestamp is too old or too far in the future
        if (createdInstant.isBefore(now.minusSeconds(MAX_AGE_SECONDS))) {
            System.err.println("Timestamp validation failed: 'wsu:Created' is too old. Created: " + createdInstant + ", now: " + now);
            return false;
        }
        if (createdInstant.isAfter(now.plusSeconds(CLOCK_SKEW_TOLERANCE_SECONDS))) {
            System.err.println("Timestamp validation failed: 'wsu:Created' is in the future. Created: " + createdInstant + ", now: " + now);
            return false;
        }

        // 2. Handle 'wsu:Expires' if present
        Instant expiryInstant;
        if (expires != null && !expires.isEmpty()) {
            try {
                expiryInstant = ZonedDateTime.parse(expires).toInstant();
            } catch (DateTimeParseException e) {
                System.err.println("Timestamp validation failed: Invalid 'wsu:Expires' format: " + expires);
                return false;
            }

            if (expiryInstant.isBefore(now)) {
                System.err.println("Timestamp validation failed: 'wsu:Expires' is in the past. Expires: " + expiryInstant + ", now: " + now);
                return false;
            }
            if (expiryInstant.isBefore(createdInstant)) {
                System.err.println("Timestamp validation failed: 'wsu:Expires' is before 'wsu:Created'. Created: " + createdInstant + ", Expires: " + expiryInstant);
                return false;
            }
        } else {
            // If 'wsu:Expires' is not provided, use a default expiry based on 'wsu:Created' and MAX_AGE_SECONDS
            expiryInstant = createdInstant.plusSeconds(MAX_AGE_SECONDS);
            if (expiryInstant.isBefore(now)) {
                System.err.println("Timestamp validation failed: Default expiry for 'wsu:Created' is in the past. Calculated Expires: " + expiryInstant + ", now: " + now);
                return false;
            }
        }

        // 3. Replay protection
        String cacheKey = (timestampId != null && !timestampId.isEmpty()) ? timestampId : created;
        if (activeTimestamps.containsKey(cacheKey)) {
            System.err.println("Timestamp validation failed: Replay detected for key: " + cacheKey);
            return false;
        }

        // If all checks pass, add to cache with its calculated/explicit expiry
        activeTimestamps.put(cacheKey, expiryInstant);
        return true;
    }

    public static void clearCache() {
        activeTimestamps.clear();
    }
}

